import{_ as s,o as e,c as p,ag as i}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),n={name:"guide/getting-started.md"};function t(l,a,d,o,h,c){return e(),p("div",null,[...a[0]||(a[0]=[i(`<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>好了，别想太多，跟我来。</p><p>两分钟，让你跑通第一个内容。</p><hr><h2 id="第一步-装好依赖" tabindex="-1">第一步：装好依赖 <a class="header-anchor" href="#第一步-装好依赖" aria-label="Permalink to &quot;第一步：装好依赖&quot;">​</a></h2><p>你只需要一个东西：Bun。这是新一代的 JavaScript 运行时，跑起来比 Node 快得多，而且安装超级简单。</p><p>打开你的终端，输入：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>然后等着。看到 <code>✨ Done</code> 就完事了。</p><p>如果你还没有装 Bun，一行命令就搞定：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://bun.sh/install</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>装好了？好，我们继续。</p><hr><h2 id="第二步-初始化" tabindex="-1">第二步：初始化 <a class="header-anchor" href="#第二步-初始化" aria-label="Permalink to &quot;第二步：初始化&quot;">​</a></h2><p>在你的项目目录里（就是你想放内容的地方），跑：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xhsops</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>跑完这行，你的目录里会多出一个 <code>.xhsops/</code> 文件夹。恭喜你，你已经有自己的内容运营仓库了。</p><p>这个文件夹里现在还是空的，别管它。后面 AI 会帮你往里塞东西。</p><p>然后呢？</p><p>然后你基本上就不用再碰终端了。之后的所有操作，都在你常用的 AI 工具（Claude Code、Cursor、Windsurf 随便哪个）里完成。</p><hr><h2 id="第三步-填品牌资料" tabindex="-1">第三步：填品牌资料 <a class="header-anchor" href="#第三步-填品牌资料" aria-label="Permalink to &quot;第三步：填品牌资料&quot;">​</a></h2><p>这是唯一需要你动手的事，也是最重要的事。</p><p>为什么？因为 AI 要靠这些来理解你是谁、你在对谁说话、你说的话是什么风格。没有这些，它写出来的东西就是一堆没有灵魂的文字。</p><p>打开这几个文件，照着模板填：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.xhsops/brand/</span></span>
<span class="line"><span>├── profile.md    # 你是谁</span></span>
<span class="line"><span>├── audience.md   # 你的读者是谁</span></span>
<span class="line"><span>├── offer.md      # 你提供什么价值</span></span>
<span class="line"><span>├── tone.md       # 你的语气风格</span></span>
<span class="line"><span>└── taboo.md      # 你不写什么</span></span></code></pre></div><p>我一家一家说：</p><p><strong>profile.md</strong> —— 你是谁。不用写人生故事，几句话就行。比如：「程序员，8 年工作经验，现在做 AI 创业。」</p><p><strong>audience.md</strong> —— 谁在看你的笔记。同样，几句话：「同样是程序员，工作 1-5 年，想提升效率但不想卷的人。」</p><p><strong>offer.md</strong> —— 你能帮他们解决什么问题。「帮助程序员用 AI 工具把重复工作自动化，省下时间做有意思的事。」</p><p><strong>tone.md</strong> —— 你怎么说话。「像在和技术朋友聊天，直接、实在、偶尔带点吐槽。」</p><p><strong>taboo.md</strong> —— 什么你不写。「不写纯吹水的 AI 焦虑，不写程序员之外的领域，不写太长没人看完的东西。」</p><p>不用写太多，能有个大概就行。5 分钟就能填完。</p><p>填完这个，你会发现一个有趣的事——以后 AI 写的每篇内容，都带着你的影子。</p><hr><h2 id="第四步-开干" tabindex="-1">第四步：开干 <a class="header-anchor" href="#第四步-开干" aria-label="Permalink to &quot;第四步：开干&quot;">​</a></h2><p>打开你的 AI 工具，直接说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我写一篇：程序员如何用 AI 做周报</span></span></code></pre></div><p>就这么简单。</p><p>AI 会自己：</p><ol><li>读取你的品牌配置——它知道你是谁了</li><li>创建一个工作目录——在 <code>.xhsops/quick/</code> 下面</li><li>生成一个 brief——就是&quot;我要怎么写&quot;的计划</li><li>写出第一版初稿——draft.md</li></ol><p>你可能会看到一些 <code>&lt;placeholder&gt;...&lt;/placeholder&gt;</code> 的标记。这是 AI 告诉你：「这块我没想好，你给点意见。」</p><p>你只需要做三件事：</p><ul><li>确认方向对不对</li><li>提意见：「这里可以更直接一点」「例子可以换一个」</li><li>让它改：「帮我改一下第三段」</li></ul><p>别担心说错话。AI 不会生气，你随时可以推翻重来。</p><hr><h2 id="第五步-审核和发布" tabindex="-1">第五步：审核和发布 <a class="header-anchor" href="#第五步-审核和发布" aria-label="Permalink to &quot;第五步：审核和发布&quot;">​</a></h2><p>稿子改得差不多了，你继续在 AI 工具里说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我审核刚才那篇</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:review</span></span></code></pre></div><p>AI 会根据一套规则检查：</p><ul><li>语气对不对——还是不是你的声音</li><li>CTA 放的位置合不合理——有没有在合适的地方要互动</li><li>有没有 placeholder 没收干净——有没有没填完的地方</li><li>结构清不清晰——开头能不能抓住人，中间有没有干货，结尾有没有引导</li></ul><p>审完了会生成一个 <code>review.md</code>，告诉你哪里通过、哪里要改。</p><p>如果需要改，你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>根据 review 意见帮我改一下</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:iterate</span></span></code></pre></div><p>这个循环可以跑好几轮，直到你满意为止。</p><p>稿子定稿了，终于到了发布这一步。你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我生成发布包</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:publish</span></span></code></pre></div><p>这回你会得到一个文件夹，里面有：</p><ul><li>终稿正文——可以直接复制粘贴到小红书</li><li>封面方向——标题怎么起、关键词是什么</li><li>配图建议——配什么图、哪里配</li><li>发布检查清单——发之前再确认一遍</li></ul><p>这时候才真的是「可以发」的状态。</p><hr><h2 id="第六步-归档" tabindex="-1">第六步：归档 <a class="header-anchor" href="#第六步-归档" aria-label="Permalink to &quot;第六步：归档&quot;">​</a></h2><p>最后一步，别忘了归档。你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:archive</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我归档</span></span></code></pre></div><p>AI 会把这次创作的经验教训写进 <code>.xhsops/knowledge/winning-patterns.md</code>。下次它帮你写新内容的时候，会参考这些经验。</p><p>这是 XHSOps 最迷人的地方——不是「聊完就结束」，而是每一次都在积累。</p><hr><h2 id="就这么点事" tabindex="-1">就这么点事 <a class="header-anchor" href="#就这么点事" aria-label="Permalink to &quot;就这么点事&quot;">​</a></h2><p>真的，别想复杂了。</p><ol><li><code>bun install</code> + <code>xhsops init</code> → 一次性</li><li>填 5 个 brand 文件 → 一次性</li><li>之后就在 AI 工具里说话</li></ol><p>Slash command 是你用的，CLI 是 AI 用的。你在前面冲锋，AI 在后面帮你把一切都管理得井井有条。</p><p>常用命令就这几个：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:quick    → 创建新选题</span></span>
<span class="line"><span>/xhs:review   → 审核初稿</span></span>
<span class="line"><span>/xhs:iterate  → 根据意见修改</span></span>
<span class="line"><span>/xhs:publish  → 生成发布包</span></span>
<span class="line"><span>/xhs:archive  → 归档并总结经验</span></span>
<span class="line"><span>/xhs:status   → 看看现在进行到哪一步了</span></span></code></pre></div><p>跑起来吧。</p>`,82)])])}const u=s(n,[["render",t]]);export{g as __pageData,u as default};
